      out.write("  <!-- 3D CANVAS -->\n");
      out.write("  <div id=\"canvasWrap\">\n");
      out.write("    <canvas id=\"canvas\"></canvas>\n");
      out.write("\n");
      out.write("    <div id=\"viewToggle\">\n");
      out.write("      <button class=\"view-btn active\" onclick=\"setView('3d')\">3D</button>\n");
      out.write("      <button class=\"view-btn\"        onclick=\"setView('top')\">Top</button>\n");
      out.write("      <button class=\"view-btn\"        onclick=\"setView('front')\">Front</button>\n");
      out.write("    </div>\n");
      out.write("\n");
      out.write("    <div id=\"placingHint\">✏️ Click on grid to place element</div>\n");
      out.write("\n");
      out.write("    <div id=\"camHint\">\n");
      out.write("      <b>Left drag</b> Orbit &nbsp; <b>Right drag</b> Pan<br>\n");
      out.write("      <b>Scroll</b> Zoom &nbsp; <b>Click</b> Select/Place\n");
      out.write("    </div>\n");
      out.write("  </div>\n");
      out.write("\n");
      out.write("  <!-- RIGHT PANEL -->\n");
      out.write("  <div id=\"rightPanel\">\n");
      out.write("    <div id=\"propTitle\">Properties</div>\n");
      out.write("    <div id=\"propList\">\n");
      out.write("      <div id=\"noSelection\">Click an element to select it and edit its properties.</div>\n");
      out.write("      <div id=\"propForm\" style=\"display:none\">\n");
      out.write("        <div class=\"prop-row\"><div class=\"prop-label\">Label</div>    <input class=\"prop-val\" id=\"pLabel\"  type=\"text\"></div>\n");
      out.write("        <div class=\"prop-row\"><div class=\"prop-label\">X Position</div><input class=\"prop-val\" id=\"pX\"     type=\"number\" step=\"0.5\"></div>\n");
      out.write("        <div class=\"prop-row\"><div class=\"prop-label\">Y Position</div><input class=\"prop-val\" id=\"pY\"     type=\"number\" step=\"0.5\"></div>\n");
      out.write("        <div class=\"prop-row\"><div class=\"prop-label\">Z Position</div><input class=\"prop-val\" id=\"pZ\"     type=\"number\" step=\"0.5\"></div>\n");
      out.write("        <div class=\"prop-row\"><div class=\"prop-label\">Width</div>    <input class=\"prop-val\" id=\"pWidth\"  type=\"number\" step=\"0.5\"></div>\n");
      out.write("        <div class=\"prop-row\"><div class=\"prop-label\">Height</div>   <input class=\"prop-val\" id=\"pHeight\" type=\"number\" step=\"0.5\"></div>\n");
      out.write("        <div class=\"prop-row\"><div class=\"prop-label\">Depth</div>    <input class=\"prop-val\" id=\"pDepth\"  type=\"number\" step=\"0.5\"></div>\n");
      out.write("        <div class=\"prop-row\"><div class=\"prop-label\">Rotation°</div><input class=\"prop-val\" id=\"pRotY\"   type=\"number\" step=\"45\"></div>\n");
      out.write("        <div class=\"prop-row\"><div class=\"prop-label\">Color</div>    <input class=\"prop-color\" id=\"pColor\" type=\"color\"></div>\n");
      out.write("        <button class=\"del-btn\" onclick=\"deleteSelected()\">🗑 Delete Element</button>\n");
      out.write("      </div>\n");
      out.write("    </div>\n");
      out.write("    <div style=\"border-top:1px solid var(--border); padding:10px 12px;\">\n");
      out.write("      <div class=\"panel-title\">Elements (<span id=\"elemCount\">0</span>)</div>\n");
      out.write("      <div id=\"elemList\"></div>\n");
      out.write("    </div>\n");
      out.write("  </div>\n");
      out.write("</div>\n");
      out.write("\n");
      out.write("<div id=\"toast\"></div>\n");
      out.write("\n");
      out.write("<!-- Three.js -->\n");
      out.write("<script src=\"https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js\"></script>\n");
      out.write("<script>\n");
      out.write("// =====================================================================\n");
      out.write("//  ArchStudio — 3D Architecture Designer\n");
      out.write("//  Java Servlet backend (stores project in HttpSession)\n");
      out.write("//  Three.js frontend (3D rendering + interaction)\n");
      out.write("// =====================================================================\n");
      out.write("\n");
      out.write("const SERVLET = '");
      out.print( request.getContextPath() );
      out.write("/design';\n");
      out.write("\n");
      out.write("// ---- Scene setup ---------------------------------------------------\n");
      out.write("const canvas   = document.getElementById('canvas');\n");
      out.write("const wrap     = document.getElementById('canvasWrap');\n");
      out.write("const renderer = new THREE.WebGLRenderer({ canvas, antialias:true });\n");
      out.write("renderer.setPixelRatio(window.devicePixelRatio);\n");
      out.write("renderer.shadowMap.enabled = true;\n");
      out.write("renderer.shadowMap.type = THREE.PCFSoftShadowMap;\n");
      out.write("renderer.setClearColor(0x1a2035, 1);\n");
      out.write("\n");
      out.write("const scene  = new THREE.Scene();\n");
      out.write("scene.fog    = new THREE.FogExp2(0x1a2035, 0.025);\n");
      out.write("\n");
      out.write("const camera = new THREE.PerspectiveCamera(60, 1, 0.1, 200);\n");
      out.write("camera.position.set(15, 18, 20);\n");
      out.write("camera.lookAt(0, 0, 0);\n");
      out.write("\n");
      out.write("// ---- Lighting ------------------------------------------------------\n");
      out.write("const ambient = new THREE.AmbientLight(0x8899cc, 0.7);\n");
      out.write("scene.add(ambient);\n");
      out.write("\n");
      out.write("const sun = new THREE.DirectionalLight(0xfff5e0, 1.3);\n");
      out.write("sun.position.set(20, 40, 20);\n");
      out.write("sun.castShadow = true;\n");
      out.write("sun.shadow.mapSize.set(2048, 2048);\n");
      out.write("sun.shadow.camera.near = 0.5;\n");
      out.write("sun.shadow.camera.far  = 100;\n");
      out.write("sun.shadow.camera.left = sun.shadow.camera.bottom = -30;\n");
      out.write("sun.shadow.camera.right = sun.shadow.camera.top   =  30;\n");
      out.write("scene.add(sun);\n");
      out.write("\n");
      out.write("const fill = new THREE.DirectionalLight(0x4466aa, 0.4);\n");
      out.write("fill.position.set(-10, 5, -10);\n");
      out.write("scene.add(fill);\n");
      out.write("\n");
      out.write("// ---- Grid ----------------------------------------------------------\n");
      out.write("const gridHelper = new THREE.GridHelper(40, 40, 0x2a3347, 0x1e2535);\n");
      out.write("scene.add(gridHelper);\n");
      out.write("\n");
      out.write("// Ground plane (invisible, for raycasting)\n");
      out.write("const groundGeo = new THREE.PlaneGeometry(40, 40);\n");
      out.write("const groundMat = new THREE.MeshBasicMaterial({ visible:false, side:THREE.DoubleSide });\n");
      out.write("const ground    = new THREE.Mesh(groundGeo, groundMat);\n");
      out.write("ground.rotation.x = -Math.PI / 2;\n");
      out.write("ground.name = 'GROUND';\n");
      out.write("scene.add(ground);\n");
      out.write("\n");
      out.write("// Ghost preview mesh\n");
      out.write("const ghostGeo = new THREE.BoxGeometry(1,1,1);\n");
      out.write("const ghostMat = new THREE.MeshBasicMaterial({ color:0x4f8ef7, transparent:true, opacity:0.35, depthWrite:false });\n");
      out.write("const ghost    = new THREE.Mesh(ghostGeo, ghostMat);\n");
      out.write("ghost.visible  = false;\n");
      out.write("scene.add(ghost);\n");
      out.write("\n");
      out.write("// ---- State ---------------------------------------------------------\n");
      out.write("let currentTool  = 'WALL';\n");
      out.write("let currentMat   = 'CONCRETE';\n");
      out.write("let currentColor = '#e8e0d0';\n");
      out.write("let currentMode  = 'place';  // 'place' | 'select'\n");
      out.write("let selectedId   = null;\n");
      out.write("const meshMap    = {};        // id → THREE.Mesh\n");
      out.write("let projectData  = null;\n");
      out.write("\n");
      out.write("// Dimension inputs\n");
      out.write("const gW = () => parseFloat(document.getElementById('sWidth').value)  || 1;\n");
      out.write("const gH = () => parseFloat(document.getElementById('sHeight').value) || 3;\n");
      out.write("const gD = () => parseFloat(document.getElementById('sDepth').value)  || 0.3;\n");
      out.write("const gR = () => parseFloat(document.getElementById('sRotY').value)   || 0;\n");
      out.write("\n");
      out.write("// ---- Material → color map ------------------------------------------\n");
      out.write("const MAT_COLORS = {\n");
      out.write("  CONCRETE: '#d4cfc7', WOOD:'#c8a96e', GLASS:'#a8d8ea',\n");
      out.write("  BRICK:'#b5603f', MARBLE:'#f0ece4', METAL:'#8a9bb0'\n");
      out.write("};\n");
      out.write("\n");
      out.write("// Default sizes per type\n");
      out.write("const TYPE_DEFAULTS = {\n");
      out.write("  WALL:       {w:4,   h:3,   d:0.3},\n");
      out.write("  FLOOR:      {w:5,   h:0.2, d:5},\n");
      out.write("  ROOF:       {w:5,   h:0.3, d:5},\n");
      out.write("  DOOR:       {w:1,   h:2.2, d:0.15},\n");
      out.write("  WINDOW:     {w:1.2, h:1.2, d:0.1},\n");
      out.write("  STAIR:      {w:2,   h:2,   d:3},\n");
      out.write("  FURN_SOFA:  {w:2.2, h:0.8, d:1},\n");
      out.write("  FURN_TABLE: {w:1.5, h:0.75,d:0.8},\n");
      out.write("  FURN_BED:   {w:2,   h:0.6, d:2.2},\n");
      out.write("  FURN_BATH:  {w:1.7, h:0.6, d:0.8},\n");
      out.write("  FURN_DESK:  {w:1.5, h:0.8, d:0.7},\n");
      out.write("  FURN_PLANT: {w:0.4, h:1.2, d:0.4},\n");
      out.write("};\n");
      out.write("\n");
      out.write("// Type → display color\n");
      out.write("const TYPE_COLORS = {\n");
      out.write("  WALL:'#e8e0d0', FLOOR:'#c8b99a', ROOF:'#8a7a6a',\n");
      out.write("  DOOR:'#8b6914', WINDOW:'#add8e6', STAIR:'#a0908a',\n");
      out.write("  FURN_SOFA:'#6a8fa0', FURN_TABLE:'#b0905a',\n");
      out.write("  FURN_BED:'#9a8ab0',  FURN_BATH:'#a0c8d8',\n");
      out.write("  FURN_DESK:'#7a8a9a', FURN_PLANT:'#3a8a4a',\n");
      out.write("};\n");
      out.write("\n");
      out.write("// ---- Build mesh from element data ----------------------------------\n");
      out.write("function buildMesh(el) {\n");
      out.write("  const geo = new THREE.BoxGeometry(el.width, el.height, el.depth);\n");
      out.write("  let color = el.color || '#e8e0d0';\n");
      out.write("\n");
      out.write("  // Glass is transparent\n");
      out.write("  const isGlass = (el.material === 'GLASS' || el.type === 'WINDOW');\n");
      out.write("  const mat = new THREE.MeshLambertMaterial({\n");
      out.write("    color: new THREE.Color(color),\n");
      out.write("    transparent: isGlass,\n");
      out.write("    opacity: isGlass ? 0.45 : 1.0\n");
      out.write("  });\n");
      out.write("\n");
      out.write("  const mesh = new THREE.Mesh(geo, mat);\n");
      out.write("  mesh.position.set(el.x, el.y + el.height / 2, el.z);\n");
      out.write("  mesh.rotation.y = THREE.MathUtils.degToRad(el.rotationY || 0);\n");
      out.write("  mesh.castShadow    = true;\n");
      out.write("  mesh.receiveShadow = true;\n");
      out.write("  mesh.userData.id   = el.id;\n");
      out.write("  mesh.userData.type = el.type;\n");
      out.write("  scene.add(mesh);\n");
      out.write("  meshMap[el.id] = mesh;\n");
      out.write("  return mesh;\n");
      out.write("}\n");
      out.write("\n");
      out.write("function removeMesh(id) {\n");
      out.write("  if (meshMap[id]) { scene.remove(meshMap[id]); delete meshMap[id]; }\n");
      out.write("}\n");
      out.write("\n");
      out.write("function rebuildScene(data) {\n");
      out.write("  // Remove all element meshes\n");
      out.write("  Object.keys(meshMap).forEach(id => removeMesh(id));\n");
      out.write("  data.elements.forEach(el => buildMesh(el));\n");
      out.write("  updateStats(data);\n");
      out.write("  updateElemList(data.elements);\n");
      out.write("}\n");
      out.write("\n");
      out.write("// ---- AJAX helpers --------------------------------------------------\n");
      out.write("async function post(params) {\n");
      out.write("  const body = new URLSearchParams(params);\n");
      out.write("  const r    = await fetch(SERVLET, { method:'POST', body });\n");
      out.write("  return r.json();\n");
      out.write("}\n");
      out.write("\n");
      out.write("async function getState() {\n");
      out.write("  const r = await fetch(SERVLET + '?action=state');\n");
      out.write("  return r.json();\n");
      out.write("}\n");
      out.write("\n");
      out.write("// ---- Tool selection ------------------------------------------------\n");
      out.write("function setTool(btn, type) {\n");
      out.write("  document.querySelectorAll('.tool-btn[data-type]').forEach(b => b.classList.remove('active'));\n");
      out.write("  btn.classList.add('active');\n");
      out.write("  currentTool = type;\n");
      out.write("  // Auto-set sensible defaults\n");
      out.write("  const def = TYPE_DEFAULTS[type] || {w:1,h:3,d:0.3};\n");
      out.write("  document.getElementById('sWidth').value  = def.w;\n");
      out.write("  document.getElementById('sHeight').value = def.h;\n");
      out.write("  document.getElementById('sDepth').value  = def.d;\n");
      out.write("  if (TYPE_COLORS[type]) setColorVal(TYPE_COLORS[type]);\n");
      out.write("}\n");
      out.write("\n");
      out.write("function setMat(btn, mat) {\n");
      out.write("  document.querySelectorAll('.mat-btn').forEach(b => b.classList.remove('active'));\n");
      out.write("  btn.classList.add('active');\n");
      out.write("  currentMat = mat;\n");
      out.write("  if (MAT_COLORS[mat]) setColorVal(MAT_COLORS[mat]);\n");
      out.write("}\n");
      out.write("\n");
      out.write("function setColor(swatch, color) {\n");
      out.write("  document.querySelectorAll('.color-swatch').forEach(s => s.classList.remove('active'));\n");
      out.write("  swatch.classList.add('active');\n");
      out.write("  currentColor = color;\n");
      out.write("}\n");
      out.write("function setCustomColor(color) {\n");
      out.write("  document.querySelectorAll('.color-swatch').forEach(s => s.classList.remove('active'));\n");
      out.write("  currentColor = color;\n");
      out.write("}\n");
      out.write("function setColorVal(color) {\n");
      out.write("  currentColor = color;\n");
      out.write("  document.querySelectorAll('.color-swatch').forEach(s => {\n");
      out.write("    s.classList.toggle('active', s.dataset.c === color);\n");
      out.write("  });\n");
      out.write("}\n");
      out.write("\n");
      out.write("function setMode(mode) {\n");
      out.write("  currentMode = mode;\n");
      out.write("  document.getElementById('modePlace').classList.toggle('active',  mode === 'place');\n");
      out.write("  document.getElementById('modeSelect').classList.toggle('active', mode === 'select');\n");
      out.write("  document.getElementById('placingHint').style.display = mode === 'place' ? 'block' : 'none';\n");
      out.write("  ghost.visible = false;\n");
      out.write("}\n");
      out.write("\n");
      out.write("// ---- Raycasting ----------------------------------------------------\n");
      out.write("const raycaster = new THREE.Raycaster();\n");
      out.write("const mouse2    = new THREE.Vector2();\n");
      out.write("\n");
      out.write("function getMousePos(e) {\n");
      out.write("  const rect = canvas.getBoundingClientRect();\n");
      out.write("  mouse2.x = ((e.clientX - rect.left) / rect.width)  * 2 - 1;\n");
      out.write("  mouse2.y = -((e.clientY - rect.top)  / rect.height) * 2 + 1;\n");
      out.write("}\n");
      out.write("\n");
      out.write("function raycastGround() {\n");
      out.write("  raycaster.setFromCamera(mouse2, camera);\n");
      out.write("  const targets = [ground, ...Object.values(meshMap)];\n");
      out.write("  const hits = raycaster.intersectObjects(targets);\n");
      out.write("  return hits.length > 0 ? hits[0].point : null;\n");
      out.write("}\n");
      out.write("\n");
      out.write("function raycastMeshes() {\n");
      out.write("  raycaster.setFromCamera(mouse2, camera);\n");
      out.write("  const meshes = Object.values(meshMap);\n");
      out.write("  const hits = raycaster.intersectObjects(meshes);\n");
      out.write("  return hits.length > 0 ? hits[0].object : null;\n");
      out.write("}\n");
      out.write("\n");
      out.write("// Snap to grid\n");
      out.write("function snap(v, step=0.5) { return Math.round(v / step) * step; }\n");
      out.write("\n");
      out.write("// ---- Mouse events on canvas ----------------------------------------\n");
      out.write("canvas.addEventListener('mousemove', e => {\n");
      out.write("  if (isDragging) return;\n");
      out.write("  getMousePos(e);\n");
      out.write("  if (currentMode === 'place') {\n");
      out.write("    const pt = raycastGround();\n");
      out.write("    if (pt) {\n");
      out.write("      const w = gW(), h = gH(), d = gD();\n");
      out.write("      ghost.scale.set(w, h, d);\n");
      out.write("      // Let base Y snap to nearest 0.1, so objects sit firmly.\n");
      out.write("      const baseY = snap(pt.y, 0.1);\n");
      out.write("      ghost.position.set(snap(pt.x), baseY + h/2, snap(pt.z));\n");
      out.write("      ghost.rotation.y = THREE.MathUtils.degToRad(gR());\n");
      out.write("      ghost.visible = true;\n");
      out.write("    } else { ghost.visible = false; }\n");
      out.write("  }\n");
      out.write("});\n");
      out.write("\n");
      out.write("canvas.addEventListener('mouseleave', () => { ghost.visible = false; });\n");
      out.write("\n");
      out.write("canvas.addEventListener('click', async e => {\n");
      out.write("  if (isDragging) return;\n");
      out.write("  getMousePos(e);\n");
      out.write("\n");
      out.write("  if (currentMode === 'place') {\n");
      out.write("    const pt = raycastGround();\n");
      out.write("    if (!pt) return;\n");
      out.write("    const w = gW(), h = gH(), d = gD(), r = gR();\n");
      out.write("    const baseY = snap(pt.y, 0.1);\n");
      out.write("    const data = await post({\n");
      out.write("      action:'add', type:currentTool,\n");
      out.write("      x: snap(pt.x), y: baseY, z: snap(pt.z),\n");
      out.write("      width:w, height:h, depth:d, rotY:r,\n");
      out.write("      color:currentColor, material:currentMat,\n");
      out.write("      label:currentTool\n");
      out.write("    });\n");
      out.write("    rebuildScene(data);\n");
      out.write("    toast('✅ ' + currentTool + ' placed');\n");
      out.write("  } else {\n");
      out.write("    // Select mode\n");
      out.write("    const hit = raycastMeshes();\n");
      out.write("    if (hit) {\n");
      out.write("      selectElement(hit.userData.id);\n");
      out.write("    } else {\n");
      out.write("      deselectElement();\n");
      out.write("    }\n");
      out.write("  }\n");
      out.write("});\n");
      out.write("\n");
      out.write("canvas.addEventListener('contextmenu', e => e.preventDefault());\n");
      out.write("\n");
      out.write("// ---- Selection & Properties ----------------------------------------\n");
      out.write("function selectElement(id) {\n");
      out.write("  selectedId = id;\n");
      out.write("  // Highlight\n");
      out.write("  Object.entries(meshMap).forEach(([k, m]) => {\n");
      out.write("    m.material.emissive = new THREE.Color(k === id ? 0x224488 : 0x000000);\n");
      out.write("  });\n");
      out.write("  // Find element data\n");
      out.write("  const el = projectData?.elements.find(e => e.id === id);\n");
      out.write("  if (el) showProps(el);\n");
      out.write("  updateElemList(projectData?.elements || []);\n");
      out.write("}\n");
      out.write("\n");
      out.write("function deselectElement() {\n");
      out.write("  selectedId = null;\n");
      out.write("  Object.values(meshMap).forEach(m => m.material.emissive = new THREE.Color(0x000000));\n");
      out.write("  document.getElementById('noSelection').style.display = 'block';\n");
      out.write("  document.getElementById('propForm').style.display    = 'none';\n");
      out.write("  updateElemList(projectData?.elements || []);\n");
      out.write("}\n");
      out.write("\n");
      out.write("function showProps(el) {\n");
      out.write("  document.getElementById('noSelection').style.display = 'none';\n");
      out.write("  document.getElementById('propForm').style.display    = 'block';\n");
      out.write("  document.getElementById('pLabel').value  = el.label;\n");
      out.write("  document.getElementById('pX').value      = el.x;\n");
      out.write("  document.getElementById('pY').value      = el.y;\n");
      out.write("  document.getElementById('pZ').value      = el.z;\n");
      out.write("  document.getElementById('pWidth').value  = el.width;\n");
      out.write("  document.getElementById('pHeight').value = el.height;\n");
      out.write("  document.getElementById('pDepth').value  = el.depth;\n");
      out.write("  document.getElementById('pRotY').value   = el.rotationY;\n");
      out.write("  document.getElementById('pColor').value  = el.color || '#ffffff';\n");
      out.write("}\n");
      out.write("\n");
      out.write("// Property change → send to servlet → rebuild\n");
      out.write("async function updateProp(prop, val) {\n");
      out.write("  if (!selectedId) return;\n");
      out.write("  const data = await post({ action:'update', id:selectedId, prop, val });\n");
      out.write("  projectData = data;\n");
      out.write("  rebuildScene(data);\n");
      out.write("  // Re-select\n");
      out.write("  const el = data.elements.find(e => e.id === selectedId);\n");
      out.write("  if (el) { showProps(el); selectElement(selectedId); }\n");
      out.write("}\n");
      out.write("\n");
      out.write("// Bind property inputs\n");
      out.write("['pLabel','pX','pY','pZ','pWidth','pHeight','pDepth','pRotY','pColor'].forEach(id => {\n");
      out.write("  const el = document.getElementById(id);\n");
      out.write("  const propMap = {pLabel:'label',pX:'x',pY:'y',pZ:'z',\n");
      out.write("    pWidth:'width',pHeight:'height',pDepth:'depth',pRotY:'rotationY',pColor:'color'};\n");
      out.write("  el.addEventListener('change', () => updateProp(propMap[id], el.value));\n");
      out.write("});\n");
      out.write("\n");
      out.write("async function deleteSelected() {\n");
      out.write("  if (!selectedId) return;\n");
      out.write("  const data = await post({ action:'remove', id:selectedId });\n");
      out.write("  projectData = data;\n");
      out.write("  deselectElement();\n");
      out.write("  rebuildScene(data);\n");
      out.write("  toast('🗑 Element deleted');\n");
      out.write("}\n");
      out.write("\n");
      out.write("// ---- Element list --------------------------------------------------\n");
      out.write("function updateElemList(elements) {\n");
      out.write("  const list = document.getElementById('elemList');\n");
